import{_ as n,W as a,X as s,a0 as t}from"./framework-5f3abea5.js";const o={},p=t(`<h1 id="spring事务分析" tabindex="-1"><a class="header-anchor" href="#spring事务分析" aria-hidden="true">#</a> Spring事务分析</h1><h2 id="propagation" tabindex="-1"><a class="header-anchor" href="#propagation" aria-hidden="true">#</a> Propagation</h2><ul><li>REQUIRED：支持当前事务，如果当前没有事务，就新建一个事务。这是最常见的选择。</li><li>SUPPORTS：支持当前事务，如果当前没有事务，就以非事务方式执行。</li><li>MANDATORY：支持当前事务，如果当前没有事务，就抛出异常。</li><li>REQUIRES_NEW：新建事务，如果当前存在事务，把当前事务挂起。</li><li>NOT_SUPPORTED：以非事务方式执行操作，如果当前存在事务，就把当前事务挂起。</li><li>NEVER：以非事务方式执行，如果当前存在事务，则抛出异常。</li><li>NESTED：支持当前事务，如果当前事务存在，则执行一个嵌套事务，如果当前没有事务，就新建一个事务。</li></ul><p>Spring中默认Propagation是REQUIRED</p><h2 id="transactionsynchronizationmanager" tabindex="-1"><a class="header-anchor" href="#transactionsynchronizationmanager" aria-hidden="true">#</a> TransactionSynchronizationManager</h2><ul><li>getCurrentTransactionName: 获取当前事务名</li></ul><h2 id="事务失效情景" tabindex="-1"><a class="header-anchor" href="#事务失效情景" aria-hidden="true">#</a> 事务失效情景</h2><h3 id="propagation配置失效" tabindex="-1"><a class="header-anchor" href="#propagation配置失效" aria-hidden="true">#</a> Propagation配置失效</h3><p>Spring的事务是基于Aop实现的，因为调用同一类下的方法会导致Aop失效，所以使用@Transactional配置同一个类下的不同方法，且嵌套调用，会导致配置失效。下面看个例子</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">A</span> <span class="token punctuation">{</span>
	
    <span class="token annotation punctuation">@Transactional</span><span class="token punctuation">(</span>rollbackFor <span class="token operator">=</span> <span class="token class-name">Exception</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">,</span> propagation <span class="token operator">=</span> <span class="token class-name">Propagation</span><span class="token punctuation">.</span><span class="token constant">REQUIRED</span><span class="token punctuation">)</span>
    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">x</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    	<span class="token function">y</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token annotation punctuation">@Transactional</span><span class="token punctuation">(</span>rollbackFor <span class="token operator">=</span> <span class="token class-name">Exception</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">,</span> propagation <span class="token operator">=</span> <span class="token class-name">Propagation</span><span class="token punctuation">.</span><span class="token constant">REQUIRES_NEW</span><span class="token punctuation">)</span>
    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">y</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    	
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>期望是y方法被调用时会挂起当前事务，并新建事务。但是x中调用y情况就不一样了，因为Aop失效，y上配置的@Transactional就没有效果了，所以y并不会新建一个事务执行，而是走了x的事务。</p>`,11),e=[p];function i(c,l){return a(),s("div",null,e)}const u=n(o,[["render",i],["__file","Spring事务分析.html.vue"]]);export{u as default};
